-- NULL인 데이터 조회
SELECT * FROM 테이블명 WHERE Discount_Price IS NULL;

-- NULL이 아닌 데이터 조회
SELECT * FROM 테이블명 WHERE Discount_Price IS NOT NULL;

-- NULL 건수 확인
SELECT
  COUNT(*) AS 전체_건수,
  COUNTIF(Discount_Price IS NULL) AS NULL_건수,
  COUNTIF(Discount_Price IS NOT NULL) AS 값_존재_건수
FROM 테이블명;

